using MVZ2.GameContent.Buffs.Level;
using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Enemies;
using MVZ2.GameContent.Seeds;
using MVZ2.GameContent.Stages;
using MVZ2Logic;
using MVZ2Logic.IZombie;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Level;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.IZombie
{
    [IZombieLayoutDefinition(VanillaIZombieLayoutNames.AreUfoScpae)]
    public class AreUfoScpae : IZombieLayoutDefinition
    {
        public AreUfoScpae(string nsp, string name) : base(nsp, name, 5)
        {
            Blueprints = new NamespaceID[]
            {
                VanillaEnemyID.imp,
                VanillaBlueprintID.ufoBlue,
                VanillaEnemyID.dullahan,
            };
        }
        public override void Fill(IIZombieMap map, RandomGenerator rng)
        {
            var level = map.Level;

            SpawnAt(level, 0, 0, VanillaContraptionID.beacon);
            SpawnAt(level, 0, 1, VanillaContraptionID.forcePad);
            SpawnAt(level, 0, 2, VanillaContraptionID.teslaCoil);
            SpawnAt(level, 0, 2, VanillaEffectID.redline);
            SpawnAt(level, 0, 4, VanillaContraptionID.furnace);

            SpawnAt(level, 1, 2, VanillaEffectID.redline);
            SpawnAt(level, 1, 3, VanillaContraptionID.pistenser);
            SpawnAt(level, 1, 4, VanillaContraptionID.furnace);

            SpawnAt(level, 2, 0, VanillaContraptionID.forcePad);

            SpawnAt(level, 3, 0, VanillaContraptionID.mineTNT);
            SpawnAt(level, 3, 1, VanillaContraptionID.pistenser);

            SpawnAt(level, 4, 0, VanillaContraptionID.gravityPad);
            SpawnAt(level, 4, 1, VanillaEffectID.redline);
            SpawnAt(level, 4, 4, VanillaContraptionID.teslaCoil);
            SpawnAt(level, 4, 4, VanillaEffectID.redline);

            SpawnAt(level, 5, 0, VanillaContraptionID.pistenser);

            SpawnAt(level, 6, 3, VanillaContraptionID.goldenApple);

            SpawnAt(level, 7, 1, VanillaContraptionID.goldenApple);

            SpawnAt(level, 8, 0, VanillaContraptionID.furnace);
            SpawnAt(level, 8, 1, VanillaContraptionID.furnace);
            SpawnAt(level, 8, 4, VanillaContraptionID.teslaCoil);

            //SpawnAt(level, 3, 2, VanillaEffectID.redline);

            //var rlX = level.GetColumnX(3);       // ÁĐ×ó±ßÔµŁ¬Óë±ę×ĽşěĎßŇ»ÖÂ  
            //var rlZ = level.GetLaneCenterZ(2);   // lane 3 µÄÖĐĐÄ  
            //var rlY = level.GetGroundY(rlX, rlZ);

            //level.Spawn(VanillaEffectID.redline, new Vector3(rlX, rlY, rlZ), null);

            var buffDef = level.Content.GetBuffDefinition<DebugNoRechargeBuff>();
            if (!level.HasBuff(buffDef))
            {
                level.AddBuff(buffDef);
            }

        }
        private void SpawnAt(LevelEngine level, int column, int lane, NamespaceID entityID)
        {
            var x = level.GetEntityColumnX(column);
            var z = level.GetEntityLaneZ(lane);
            var y = level.GetGroundY(x, z);
            level.Spawn(entityID, new Vector3(x, y, z), null);
        }
    }
}
